local LxBaseState = require("LApp.component.fsm.LxBaseState")
---@class LCityPeopleBirthState:LxBaseState 小人状态--生成
local LCityPeopleBirthState = classX("LCityPeopleBirthState", LxBaseState)

function LCityPeopleBirthState:ctor()
    self._stateType = CityPeopleFsmState.Birth;
end
function LCityPeopleBirthState:Initialize()
    LxBaseState.Initialize(self)
    ---@type LCityPeopleFsm
    self._fsm = self:GetMachine();
    ---@type LCityPeopleUnit
    self._unit = self._fsm:GetVar("unit");
    self._refId = nil
end
function LCityPeopleBirthState:Dispose()
    self._fsm = nil
    self._unit = nil
    LxBaseState.Dispose(self)
end
function LCityPeopleBirthState:Execute(deltaTime)

end

function LCityPeopleBirthState:Enter()
    self.refId = self._unit._peopleRefId;
    self._unit:SetSpineAlpha(1);
    self._unit:PlayAni("idle")
    if(not ModuleCenter.People:CheckIsResident(self.refId))then
        --流民
        self._unit:SetSpineAlpha(1);
        local config = GameTable.PeopleRef[self.refId];
        local posConfig = self._unit.peopleMgr:GetResidentPosConfig(self.refId)
        local pos = Vector3.zero
        if(posConfig ~= nil)then
            pos = Vector3(posConfig.site[1] or 0,posConfig.site[2] or 0,0)
        end

        self._unit:SetPosition(pos);
        self._fsm:ChangeState(CityPeopleFsmState.Idle);
    else
        --判断是不是生病在医院住院，如果是，就出生在医院
        local inHospital = CtrlCenter.People:PeopleIsInHospital(self.refId)
        if(inHospital)then
            self:BirthToHospital()
            return
        end
        --判断是不是在民心技能1002的持续时间内，如果是，就出生在工作地点
        local inSkill = CtrlCenter.People:InSkillTime(1002)
        if(inSkill)then
            self:BirthToWork()
            return
        end
        --根据时间周期判断出生地点
        --local timeState =self._unit.peopleMgr:GetCurTimeState();
        local timeState =CtrlCenter.City:GetCurTimeState()
        --timeState = 2
        self._unit:SetCurState(timeState)
        self._unit:SetSpineAlpha(1);
        if(ModuleCenter.Story:IsNewbieRunning())then
            --self._unit:SetInStory(true)
            self._unit:SetSpineAlpha(1);
            --local config = GameTable.PeopleRef[self.refId];
            --local pos = Vector3(config.site[1] or 0,config.site[2] or 0,0)
            --self._unit:SetPosition(pos);
            --self._fsm:ChangeState(CityPeopleFsmState.Idle);
            return
        end
        if(timeState == 1)then
            --睡觉
            self._unit._peopleState = 1
            self._unit.peopleMgr:HidePeopleTextHUD(self.refId)
            self:BirthToSleep()

        elseif timeState == 2 then
            --居民，有工作的直接到工作地点，没工作的在出生点，然后去巡逻
            self._unit._peopleState = 2
            self._unit.peopleMgr:HidePeopleTextHUD(self.refId)
            self:BirthToWork()

        elseif timeState == 3 then
            --吃饭
            self._unit._peopleState = 3
            self._unit.peopleMgr:HidePeopleTextHUD(self.refId)
            self:BirthToEat()

        end
    end
end
--出生在医院
function LCityPeopleBirthState:BirthToHospital()
    self._unit._peopleState = 4
    self._unit:SetSpineAlpha(0);
    local pos = CtrlCenter.City:GetCityView()._buildingMgr:GetBuildingPos(2006)
    self._unit:SetPosition(pos);
    self._fsm:ChangeState(CityPeopleFsmState.None);

end
--出生在吃饭地方
function LCityPeopleBirthState:BirthToEat()
    self._unit._peopleState = 3
    self._unit:SetSpineAlpha(0);
    local pos = CtrlCenter.City:GetCityView()._buildingMgr:GetBuildingPos(2005)
    self._unit:SetPosition(pos);
    self._fsm:ChangeState(CityPeopleFsmState.None);

end
--出生在睡觉地方
function LCityPeopleBirthState:BirthToSleep()
    self._unit._peopleState = 1
    self._unit:SetSpineAlpha(0);
    local people = ModuleCenter.People:GetPeopleObj(self.refId).house
    local pos = self._unit.peopleMgr:GetBuildPointById(people,self.refId)

    self._unit:SetPosition(pos);
    self._fsm:ChangeState(CityPeopleFsmState.None);

end
--出生在工作地方
function LCityPeopleBirthState:BirthToWork()
    --工作

    --self._peopleBuilding == ModuleCenter.People:GetPeopleObj(self._peopleRefId).building
    if(ModuleCenter.People:GetPeopleObj(self.refId).building > 0)then
        --有工作
        self._unit._peopleState = 2
        self._unit._peopleBuilding = ModuleCenter.People:GetPeopleObj(self.refId).building
        self._unit:SetSpineAlpha(0);
        --local pos = CtrlCenter.City:GetCityView()._buildingMgr:GetBuildingPos(ModuleCenter.People:GetPeopleObj(self.refId).building)
        local people = ModuleCenter.People:GetPeopleObj(self.refId)
        local pos = self._unit.peopleMgr:GetBuildPointById(people.building,self.refId)
        self._unit:SetPosition(pos);
        self._fsm:ChangeState(CityPeopleFsmState.None);
    else
        --没工作
        self._unit:SetSpineAlpha(1);
        local config = GameTable.PeopleRef[self.refId];
        local posConfig = self._unit.peopleMgr:GetPoeplePosConfig(self.refId)
        local pos = Vector3.zero
        if(posConfig ~= nil)then
            pos = Vector3(posConfig.site1[1] or 0,posConfig.site1[2] or 0,0)
        end
        self._unit:SetPosition(pos);
        local sick = ModuleCenter.People:GetPeopleObj(self.refId).sick
        if(sick)then
            --生病，就在出生点待着
            self._fsm:ChangeState(CityPeopleFsmState.Idle);
            return
        end
        --没生病，巡逻
        self._fsm:SetVar("Patrol",true);
        self._fsm:SetVar("GoToBuilding",nil);
        self._fsm:SetVar("GotoPoint",nil);
        self._fsm:ChangeState(CityPeopleFsmState.FindPath);
    end

end

function LCityPeopleBirthState:Exit()

end
return LCityPeopleBirthState